import{_ as t,o as e,c as a,a0 as r}from"./chunks/framework.jwovEGr5.js";const m=JSON.parse('{"title":"🧭 遊戲內傳送與 TP 捷徑指令","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-Teleport-Commands.md","filePath":"Mc-Teleport-Commands.md"}'),l={name:"Mc-Teleport-Commands.md"};function n(c,o,s,d,i,h){return e(),a("div",null,[...o[0]||(o[0]=[r('<h1 id="🧭-遊戲內傳送與-tp-捷徑指令" tabindex="-1">🧭 遊戲內傳送與 TP 捷徑指令 <a class="header-anchor" href="#🧭-遊戲內傳送與-tp-捷徑指令" aria-label="Permalink to &quot;🧭 遊戲內傳送與 TP 捷徑指令&quot;">​</a></h1><p>伺服器提供了完善的傳送系統，方便玩家在廣闊的世界中穿梭。</p><hr><h2 id="🏪-1-商店傳送-shop-control" tabindex="-1">🏪 1. 商店傳送 <code>/shop control</code> <a class="header-anchor" href="#🏪-1-商店傳送-shop-control" aria-label="Permalink to &quot;🏪 1. 商店傳送 `/shop control`&quot;">​</a></h2><ul><li>當您在網頁端點選商店座標，或是取得商店列表時，可以使用指令： <strong><code>/shop control &lt;X&gt;,&lt;Y&gt;,&lt;Z&gt;</code></strong><ul><li><em>範例</em>：<code>/shop control 100,64,-200</code></li></ul></li><li>執行後，系統會檢測安全傳送點，並將您瞬間傳送至該商店前面。</li></ul><hr><h2 id="🏠-2-個人傳送指令" tabindex="-1">🏠 2. 個人傳送指令 <a class="header-anchor" href="#🏠-2-個人傳送指令" aria-label="Permalink to &quot;🏠 2. 個人傳送指令&quot;">​</a></h2><ul><li><strong><code>/sethome [名稱]</code></strong>：在您當前站立的位置設定一個家。</li><li><strong><code>/home [名稱]</code></strong>：傳送回您設定的家。</li><li><strong><code>/spawn</code></strong>：傳送回伺服器的主出生點（大廳）。</li><li><strong><code>/back</code></strong>：傳送回您上一次死亡的位置或是上一次傳送前的位置。</li></ul><hr><h2 id="👥-3-玩家間傳送-tpa" tabindex="-1">👥 3. 玩家間傳送 (TPA) <a class="header-anchor" href="#👥-3-玩家間傳送-tpa" aria-label="Permalink to &quot;👥 3. 玩家間傳送 (TPA)&quot;">​</a></h2><ul><li><strong><code>/tpa &lt;玩家名稱&gt;</code></strong>：請求傳送至該玩家的位置。</li><li><strong><code>/tpahere &lt;玩家名稱&gt;</code></strong>：請求該玩家傳送至您的位置。</li><li><strong><code>/tpaccept</code></strong>：接受其他玩家的傳送請求。</li><li><strong><code>/tpdeny</code></strong>：拒絕傳送請求。</li></ul>',11)])])}const g=t(l,[["render",n]]);export{m as __pageData,g as default};
